# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests
import base64
import json

URL = 'http://localhost:15672'
USER = 'guest'
PASSWORD = 'guest'

headers = {
    'Authorization': f'Basic {base64.b64encode(f"{USER}:{PASSWORD}".encode("ascii")).decode("ascii")}',
    'Content-Type': 'application/json',
}

def create_vhost(name):
    data = json.dumps({'vhost': name})
    response = requests.post(f"{URL}/api/exchanges", headers=headers, data=data)
    return response.json()['id']

def create_user(username, password):
    data = json.dumps({'password': password})
    response = requests.put(f"{URL}/api/users/{username}", headers=headers, data=data)
    return response.status_code == 204

def grant_permissions(vhost, username, read_write=True):
    user_permissions = {
        'configuration': {'.*': '.*' if read_write else None},
        'exchange': {'.*': '.*' if read_write else None},
        'queue': {'.*': '.*' if read_write else None},
        'topic': {'.*': '.*' if read_write else None}
    }

    for perm, rules in user_permissions.items():
        for rule in rules:
            data = json.dumps({
                'vhost': vhost,
                'username': username,
                'type': perm,
                'level': 'all',
                'pattern': rule
            })
            response = requests.put(f"{URL}/api/permissions", headers=headers, data=data)
            if response.status_code != 204:
                print(response.text)

# Create or get vhosts for different applications
vhost_app1 = create_vhost('app1')
vhost_app2 = create_vhost('app2')

# Create users and grant permissions
create_user('user1', 'password1')
create_user('user2', 'password2')
grant_permissions(vhost_app1, 'user1', read_write=True)
grant_permissions(vhost_app2, 'user2', read_write=False)